    <div class="container">
        <h1>🔍 Multi-Stream Correlation</h1>
        <div class="subtitle">
            HUD PIT · NPI (Non‑Profiteers) · Environmental ESA — cross‑referenced by state
        </div>

        <div class="code-block">
            <pre id="queryDisplay"><span class="comment">-- MULTI-STREAM CORRELATION EXECUTION</span>
<span class="comment">-- CROSS-REFERENCING HUD PIT MATRIX, NPI DELTAS, AND ENVIRONMENTAL ESAs</span>

<span class="keyword">WITH</span> PIT_Metrics <span class="keyword">AS</span> (
  <span class="comment">-- Stream 2: Aggregate HUD Point-in-Time Counts per State</span>
  <span class="keyword">SELECT</span>
    state,
    <span class="function">SUM</span>(pit.total_homeless) <span class="keyword">AS</span> total_homeless_population,
    <span class="function">SUM</span>(pit.sheltered_homeless) <span class="keyword">AS</span> total_sheltered,
    <span class="function">SUM</span>(pit.unsheltered_homeless) <span class="keyword">AS</span> total_unsheltered,
    <span class="function">MAX</span>(pit.count_year) <span class="keyword">AS</span> latest_pit_year
  <span class="keyword">FROM</span> <span class="table">`noble-beanbag-497411-m4.national_audits.all_state_records`</span>,
  <span class="function">UNNEST</span>(hud_pit_list) <span class="keyword">AS</span> pit
  <span class="keyword">GROUP BY</span> state
),

NPI_Metrics <span class="keyword">AS</span> (
  <span class="comment">-- Stream 4: Flatten corporate leakage parameters per State</span>
  <span class="keyword">SELECT</span>
    state,
    <span class="function">COUNT</span>(npi.npi_id) <span class="keyword">AS</span> total_active_shell_entities,
    <span class="function">SUM</span>(npi.unaccounted_fund_delta) <span class="keyword">AS</span> aggregate_unaccounted_leakage
  <span class="keyword">FROM</span> <span class="table">`noble-beanbag-497411-m4.national_audits.all_state_records`</span>,
  <span class="function">UNNEST</span>(non_profiteers_index) <span class="keyword">AS</span> npi
  <span class="keyword">GROUP BY</span> state
),

ESA_Metrics <span class="keyword">AS</span> (
  <span class="comment">-- Stream 5: Isolate toxic footprints per State</span>
  <span class="keyword">SELECT</span>
    state,
    <span class="function">COUNT</span>(esa.site_id) <span class="keyword">AS</span> total_monitored_toxic_sites,
    <span class="function">COUNTIF</span>(esa.test_multiplier >= 10.0) <span class="keyword">AS</span> severe_chemical_safety_breaches,
    <span class="function">MAX</span>(<span class="keyword">CASE WHEN</span> esa.site_id = <span class="string">'ENV-HBNC-001'</span> <span class="keyword">THEN</span> esa.test_multiplier <span class="keyword">ELSE</span> <span class="keyword">NULL END</span>) <span class="keyword">AS</span> target_hbnc_crvi_multiplier
  <span class="keyword">FROM</span> <span class="table">`noble-beanbag-497411-m4.national_audits.all_state_records`</span>,
  <span class="function">UNNEST</span>(environmental_site_assessments) <span class="keyword">AS</span> esa
  <span class="keyword">GROUP BY</span> state
)

<span class="keyword">SELECT</span>
  base.state,
  base.state_name,
  pit.latest_pit_year,
  pit.total_homeless_population,
  pit.total_unsheltered,
  npi.total_active_shell_entities,
  npi.aggregate_unaccounted_leakage,
  esa.total_monitored_toxic_sites,
  esa.severe_chemical_safety_breaches,
  esa.target_hbnc_crvi_multiplier <span class="keyword">AS</span> hbnc_toxic_excess_rate
<span class="keyword">FROM</span> <span class="table">`noble-beanbag-497411-m4.national_audits.all_state_records`</span> <span class="keyword">AS</span> base
<span class="keyword">LEFT JOIN</span> PIT_Metrics <span class="keyword">AS</span> pit <span class="keyword">ON</span> base.state = pit.state
<span class="keyword">LEFT JOIN</span> NPI_Metrics <span class="keyword">AS</span> npi <span class="keyword">ON</span> base.state = npi.state
<span class="keyword">LEFT JOIN</span> ESA_Metrics <span class="keyword">AS</span> esa <span class="keyword">ON</span> base.state = esa.state
