from tqdm import tqdm

# ============================================================
# CONFIGURATION
# ============================================================
INPUT_CSV = "HB_OutOfState_LLCs.csv"          # Your extracted LLC list
OUTPUT_CSV = "rico_evidence_matrix.csv"       # Final output
PPP_TIER1 = "public_150k_plus_240930.csv"     # Over $150k
PPP_TIER2 = "ppp_up_to_150k.csv"              # Under $150k (download separately)

NONPROFIT_API_BASE = "https://projects.propublica.org/nonprofits/api/v2"

# ============================================================
# 1. ENTITY NAME CLEANING
# ============================================================
def clean_entity_name(name: str) -> str:
    if not isinstance(name, str):
        return ""
    name = name.upper()
    name = re.sub(r'[.,\-&/()]', ' ', name)
    name = re.sub(r'\s+', ' ', name)
    return name.strip()

# ============================================================
# 2. LOAD AND COMBINE PPP DATA (BOTH TIERS)
# ============================================================
def load_and_combine_ppp() -> pd.DataFrame:
    """Load both SBA tiers, clean, and concatenate."""
    combined = pd.DataFrame()
    for file in [PPP_TIER1, PPP_TIER2]:
        try:
            df = pd.read_csv(file, low_memory=False)
            df['clean_name'] = df['BusinessName'].apply(clean_entity_name)
            df['Zip'] = df['Zip'].astype(str).str[:5]
            cols = ['clean_name', 'BusinessName', 'City', 'State', 'Zip',
                    'LoanAmount', 'DateApproved', 'ForgivenessAmount']
            df = df[[c for c in cols if c in df.columns]]
            print(f"[+] Loaded {len(df):,} records from {file}")
            combined = pd.concat([combined, df], ignore_index=True)
        except FileNotFoundError:
            print(f"[!] Warning: {file} not found. Skipping.")
    print(f"[PPP] Combined total: {len(combined):,} records.")
    return combined

# ============================================================
# 3. MATCHING ENGINE (Exact + ZIP Fallback)
# ============================================================
def match_ppp_all_tiers(llc_row: dict, ppp_df: pd.DataFrame) -> List[Dict]:
    llc_name = clean_entity_name(llc_row.get("llc_name", ""))
    llc_zip = str(llc_row.get("property_zip", ""))[:5]
    matches = []

    # Exact name match
    exact = ppp_df[ppp_df['clean_name'] == llc_name]
    if not exact.empty:
        for _, row in exact.iterrows():
            matches.append({
                "match_type": "Exact Name",
                "business_name": row.get("BusinessName", ""),
                "loan_amount": row.get("LoanAmount", 0),
                "forgiven": row.get("ForgivenessAmount", 0),
                "city": row.get("City", ""),
                "state": row.get("State", ""),
                "zip": row.get("Zip", "")
            })
        return matches

    # ZIP fallback (if valid ZIP)
    if len(llc_zip) == 5:
        zip_hits = ppp_df[ppp_df['Zip'] == llc_zip]
        if not zip_hits.empty:
            for _, row in zip_hits.head(5).iterrows():
                matches.append({
                    "match_type": "ZIP Fallback",
                    "business_name": row.get("BusinessName", ""),
                    "loan_amount": row.get("LoanAmount", 0),
                    "forgiven": row.get("ForgivenessAmount", 0)
                })
    return matches

# ============================================================
# 4. IRS 990 (NONPROFIT EXPLORER API)
# ============================================================
def search_nonprofit(ein: str = None, name: str = None) -> Optional[Dict]:
    params = {}
    if ein:
        params["ein"] = ein
    elif name:
        params["q"] = name
    else:
        return None
    url = f"{NONPROFIT_API_BASE}/search.json"
    try:
        resp = requests.get(url, params=params, timeout=10)
        if resp.status_code == 200:
            data = resp.json()
            if data.get("organizations"):
                return data["organizations"][0]
    except Exception as e:
        print(f"[990] Error: {e}")
    return None

def get_990_filings(ein: str) -> List[Dict]:
    url = f"{NONPROFIT_API_BASE}/organizations/{ein}.json"
    try:
        resp = requests.get(url, timeout=10)
        if resp.status_code == 200:
            data = resp.json()
            return data.get("filings", [])
    except Exception:
        pass
    return []

